import React from "react";
import { Alert } from "flowbite-react";
import "./index.css";

const App = () => {
  return (
    <div>
      <h1>Redux Testing with Movie App</h1>
      <Alert color="success">
        <span className="font-medium">
          <p>
            <span>Change a few things up and try submitting again.</span>
          </p>
        </span>
      </Alert>
    </div>
  );
};

export default App;
